import React from "react";
import type {IKitsInputNumber} from "@lmb/kitsconcerto-types";
import KitsContainer from "../../Helpers/FormContainer";
import {clampNumber, formatNumber, parseLooseNumber,} from "../../Helpers/native/numberFormat";
import {Input, InputField} from "@lmb/kitsconcertomobile";
import Addons from "../../Helpers/Addons";
import {useComponentDefaults} from "@lmb/kitsconcerto/Hooks";

const KitsInputNumber = ({ref, ...rawProps}: IKitsInputNumber) => {
    const { mergedProps: props, themeStyle } = useComponentDefaults('InputNumber', rawProps, 'Input');
    const {
        id,
        label,
        required,
        value,
        defaultValue,
        errors,
        hideError,
        invalid,
        isFloatedLabel,
        disabled,
        helperText,
        localProps,
        onChange,

        leftAddon,
        rightAddon,
        // Prime-like numeric props
        locale,
        useGrouping,
        minFractionDigits,
        maxFractionDigits,
        mode,
        currency,
        prefix,
        suffix,
        min,
        max,

        ...rest
    } = props as any;

    /** 🔑 CONTROL DETECTION (ONLY value decides) */
    const isControlled = value !== undefined;

    /** 🔹 Internal numeric value (uncontrolled mode only) */
    const [internalNumber, setInternalNumber] = React.useState<number | null>(
        defaultValue ?? null
    );

    /** 🔹 Display text */
    const [text, setText] = React.useState<string>(() => {
        const n =
            isControlled
                ? value
                : internalNumber;

        return typeof n === "number"
            ? formatNumber(n, {
                locale,
                useGrouping,
                minFractionDigits,
                maxFractionDigits,
                mode,
                currency,
                prefix,
                suffix,
                min,
                max,
            })
            : "";
    });

    /** 🔄 Sync when controlled value changes */
    React.useEffect(() => {
        if (isControlled) {
            if (typeof value === "number") {
                setText(
                    formatNumber(value, {
                        locale,
                        useGrouping,
                        minFractionDigits,
                        maxFractionDigits,
                        mode,
                        currency,
                        prefix,
                        suffix,
                        min,
                        max,
                    })
                );
            } else {
                setText("");
            }
        }
    }, [
        isControlled,
        value,
        locale,
        useGrouping,
        minFractionDigits,
        maxFractionDigits,
        mode,
        currency,
        prefix,
        suffix,
        min,
        max,
    ]);

    /** 📤 Emit Prime-like change */
    const emitChange = (n: number | null) => {
        onChange?.({value: n} as any);
    };

    /** ✍️ Typing handler */
    const onChangeText = (raw: string) => {
        setText(raw);

        const parsed = parseLooseNumber(raw);
        if (parsed == null) {
            if (!isControlled) setInternalNumber(null);
            emitChange(null);
            return;
        }

        const clamped = clampNumber(parsed, min, max);

        if (!isControlled) {
            setInternalNumber(clamped);
        }

        emitChange(clamped);
    };

    /** 🎯 Format on blur */
    const onBlur = () => {
        const parsed = parseLooseNumber(text);
        if (parsed == null) return;

        const clamped = clampNumber(parsed, min, max);

        setText(
            formatNumber(clamped, {
                locale,
                useGrouping,
                minFractionDigits,
                maxFractionDigits,
                mode,
                currency,
                prefix,
                suffix,
                min,
                max,
            })
        );
    };

    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            errors={errors}
            invalid={invalid}
            label={label}
            hideError={hideError}
            required={required}
            disabled={disabled}
        >
            <Input
                {...(localProps as any)}
                isDisabled={!!disabled}
                isInvalid={!!invalid}
                {...(rest as any)}
                style={{width: "100%", ...(themeStyle as any)}}
            >
                <Addons leftAddon={leftAddon} rightAddon={rightAddon} invalid={!!invalid}>
                    <InputField
                        ref={ref as any}
                        value={text}
                        keyboardType="numeric"
                        onChangeText={onChangeText}
                        onBlur={onBlur}
                        editable={!disabled}
                    />
                </Addons>
            </Input>
        </KitsContainer>
    );
};

export default KitsInputNumber;
